import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define the custom CUDA kernel for Softsign activation
softsign_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <cmath>

template<typename T>
__global__ void softsign_kernel(const T* input, T* output, int size) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < size) {
        T val = input[idx];
        output[idx] = val / (1.0f + fabsf(val));
    }
}

template<>
__global__ void softsign_kernel<half>(const half* input, half* output, int size) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < size) {
        float val = __half2float(input[idx]);
        output[idx] = __float2half(val / (1.0f + fabsf(val)));
    }
}

torch::Tensor softsign_cuda(torch::Tensor input) {
    auto size = input.numel();
    auto output = torch::empty_like(input);

    const int block_size = 256;
    const int num_blocks = (size + block_size - 1) / block_size;

    AT_DISPATCH_FLOATING_TYPES_AND_HALF(input.scalar_type(), "softsign_cuda", [&] {
        softsign_kernel<scalar_t><<<num_blocks, block_size>>>(
            input.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            size
        );
    });

    return output;
}
"""

softsign_cpp_source = "torch::Tensor softsign_cuda(torch::Tensor input);"

# Compile the inline CUDA code for Softsign
softsign_module = load_inline(
    name="softsign",
    cpp_sources=softsign_cpp_source,
    cuda_sources=softsign_source,
    functions=["softsign_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=[""],
    with_cuda=True,
)

class ModelNew(nn.Module):
    """
    Optimized model that performs Softsign activation using custom CUDA kernel.
    """
    def __init__(self):
        super(ModelNew, self).__init__()
        self.softsign_op = softsign_module

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """
        Applies Softsign activation to the input tensor using custom CUDA kernel.

        Args:
            x (torch.Tensor): Input tensor of any shape.

        Returns:
            torch.Tensor: Output tensor with Softsign applied, same shape as input.
        """
        # Only use custom kernel if tensor is on CUDA
        if x.is_cuda:
            return self.softsign_op.softsign_cuda(x)
        else:
            # Fallback to PyTorch implementation for CPU tensors
            return x / (1 + torch.abs(x))

